input.content:
:root {
  --bg: #05060a;
  --panel: rgba(16, 19, 28, 0.86);
  --panel-solid: #11141d;
  --border: rgba(120, 140, 180, 0.18);
  --text: #d6dcec;
  --muted: #8a93a8;
  --accent: #ffd166;
  --pha: #ff6a35;
  --sentry: #ff4dd2;
  --comet: #74f2ff;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  height: 100%;
  overflow: hidden;
  background: var(--bg);
  color: var(--text);
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica,
    Arial, sans-serif;
  font-size: 13px;
  -webkit-font-smoothing: antialiased;
}

#app { position: fixed; inset: 0; }
canvas { display: block; }

/* ---- loading ---- */
#loading {
  position: fixed; inset: 0; z-index: 50;
  display: flex; flex-direction: column; gap: 16px;
  align-items: center; justify-content: center;
  background: var(--bg); color: var(--muted);
}
#loading.hidden { display: none; }
.spinner {
  width: 34px; height: 34px; border-radius: 50%;
  border: 3px solid rgba(255,255,255,0.12);
  border-top-color: var(--accent);
  animation: spin 0.8s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

/* ---- panels ---- */
.panel {
  position: fixed;
  background: var(--panel);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid var(--border);
  border-radius: 12px;
  box-shadow: 0 10px 40px rgba(0,0,0,0.5);
}

/* top bar / title */
#topbar {
  top: 14px; left: 14px;
  padding: 12px 16px;
  max-width: 320px;
}
#topbar h1 {
  margin: 0 0 3px; font-size: 15px; font-weight: 650;
  letter-spacing: 0.2px;
}
#topbar .sub { color: var(--muted); font-size: 11.5px; line-height: 1.45; }
#topbar .counts { margin-top: 8px; display: flex; gap: 12px; flex-wrap: wrap; }
#topbar .counts span { color: var(--muted); }
#topbar .counts b { color: var(--text); font-weight: 600; }

/* ---- controls (left) ---- */
#controls {
  left: 14px; top: 132px;
  width: 290px;
  padding: 14px 16px;
  max-height: calc(100vh - 320px);
  overflow-y: auto;
}
#controls h2 {
  font-size: 11px; text-transform: uppercase; letter-spacing: 0.8px;
  color: var(--muted); margin: 0 0 8px; font-weight: 600;
}
#controls .group { margin-bottom: 16px; }
#controls label { display: block; margin-bottom: 5px; color: var(--muted); font-size: 11.5px; }
#controls input[type="text"],
#controls input[type="date"],
#controls select {
  width: 100%; padding: 7px 9px;
  background: rgba(0,0,0,0.32);
  border: 1px solid var(--border); border-radius: 7px;
  color: var(--text); font-size: 12.5px; font-family: inherit;
}
#controls input[type="range"] { width: 100%; accent-color: var(--accent); }
.row { display: flex; gap: 8px; align-items: center; }
.row > * { flex: 1; }
.chk { display: flex !important; align-items: center; gap: 7px; cursor: pointer; color: var(--text); margin-bottom: 6px; }
.chk input { accent-color: var(--accent); }
.rangeval { color: var(--text); font-variant-numeric: tabular-nums; }
.legend { display: flex; flex-direction: column; gap: 4px; font-size: 11px; }
.legend .dot { display: inline-block; width: 9px; height: 9px; border-radius: 50%; margin-right: 6px; vertical-align: middle; }

button {
  font-family: inherit; cursor: pointer;
  background: rgba(255,255,255,0.06);
  border: 1px solid var(--border); border-radius: 7px;
  color: var(--text); padding: 7px 10px; font-size: 12px;
  transition: background 0.12s, border-color 0.12s;
}
button:hover { background: rgba(255,255,255,0.12); }
button.primary { background: var(--accent); color: #1a1300; border-color: var(--accent); font-weight: 600; }
button.primary:hover { filter: brightness(1.08); }
button.active { background: rgba(255,209,102,0.18); border-color: var(--accent); color: var(--accent); }

/* ---- timebar (bottom) ---- */
#timebar {
  left: 50%; transform: translateX(-50%);
  bottom: 16px;
  padding: 12px 18px;
  width: min(720px, calc(100vw - 28px));
  display: flex; flex-direction: column; gap: 10px;
}
#timebar .line1 { display: flex; align-items: center; gap: 14px; }
#timebar .date { font-size: 16px; font-weight: 600; font-variant-numeric: tabular-nums; min-width: 150px; }
#timebar .rate { color: var(--muted); font-size: 11.5px; }
#timebar .spacer { flex: 1; }
#timebar .btns { display: flex; gap: 6px; }
#playbtn { width: 40px; font-size: 14px; }
#timebar input[type="range"] { width: 100%; accent-color: var(--accent); }
#timebar .scrubwrap { display: flex; align-items: center; gap: 10px; }
#timebar .scrubwrap span { color: var(--muted); font-size: 10.5px; white-space: nowrap; }
.ratebtns { display: flex; gap: 4px; }
.ratebtns button { padding: 4px 8px; font-size: 11px; }

/* ---- detail panel (right) ---- */
#detail {
  right: 14px; top: 14px;
  width: 320px;
  max-height: calc(100vh - 28px);
  display: none;
  flex-direction: column;
}
#detail.open { display: flex; }
#detail .head {
  padding: 14px 16px 10px; border-bottom: 1px solid var(--border);
  display: flex; justify-content: space-between; align-items: flex-start; gap: 8px;
}
#detail .head h2 { margin: 0; font-size: 15px; font-weight: 650; line-height: 1.25; }
#detail .head .desig { color: var(--muted); font-size: 11.5px; margin-top: 2px; }
#detail .close { background: none; border: none; font-size: 18px; color: var(--muted); padding: 0 4px; }
#detail .body { padding: 12px 16px; overflow-y: auto; }
#detail .tags { display: flex; gap: 6px; flex-wrap: wrap; margin-bottom: 12px; }
.tag { font-size: 10.5px; padding: 3px 8px; border-radius: 20px; font-weight: 600; letter-spacing: 0.3px; }
.tag.pha { background: rgba(255,106,53,0.18); color: var(--pha); border: 1px solid rgba(255,106,53,0.4); }
.tag.sentry { background: rgba(255,77,210,0.16); color: var(--sentry); border: 1px solid rgba(255,77,210,0.4); }
.tag.comet { background: rgba(116,242,255,0.14); color: var(--comet); border: 1px solid rgba(116,242,255,0.4); }
.tag.class { background: rgba(120,140,180,0.16); color: #aab6cc; border: 1px solid var(--border); }
.kv { display: grid; grid-template-columns: 1fr auto; gap: 4px 10px; margin-bottom: 14px; }
.kv .k { color: var(--muted); }
.kv .v { text-align: right; font-variant-numeric: tabular-nums; }
#detail h3 { font-size: 11px; text-transform: uppercase; letter-spacing: 0.6px; color: var(--muted); margin: 14px 0 8px; }
.risk { background: rgba(255,77,210,0.08); border: 1px solid rgba(255,77,210,0.25); border-radius: 8px; padding: 10px 12px; margin-bottom: 12px; }
.ca-list { display: flex; flex-direction: column; gap: 6px; max-height: 220px; overflow-y: auto; }
.ca-item { display: grid; grid-template-columns: 1fr auto; gap: 2px 8px; font-size: 11.5px; padding: 7px 9px; background: rgba(0,0,0,0.25); border-radius: 6px; border-left: 2px solid var(--border); }
.ca-item.soon { border-left-color: var(--pha); }
.ca-item .cd { font-weight: 600; }
.ca-item .dist { text-align: right; font-variant-numeric: tabular-nums; }
.ca-item .meta { color: var(--muted); font-size: 10.5px; grid-column: 1 / -1; }
#detail .actions { display: flex; gap: 6px; margin-top: 10px; }
#detail .actions button { flex: 1; }

/* ---- search results dropdown ---- */
#results {
  position: absolute; z-index: 30;
  background: var(--panel-solid);
  border: 1px solid var(--border); border-radius: 8px;
  max-height: 260px; overflow-y: auto;
  width: 258px; margin-top: 2px;
  display: none;
  box-shadow: 0 10px 30px rgba(0,0,0,0.6);
}
#results.open { display: block; }
.result {
  padding: 8px 11px; cursor: pointer; border-bottom: 1px solid rgba(255,255,255,0.04);
  display: flex; justify-content: space-between; gap: 8px;
}
.result:hover { background: rgba(255,255,255,0.07); }
.result .nm { color: var(--text); }
.result .cls { color: var(--muted); font-size: 10.5px; }

/* planet labels */
.plabel {
  position: absolute; transform: translate(-50%, -140%);
  color: #c8d2e6; font-size: 11px; pointer-events: none;
  text-shadow: 0 1px 4px #000; white-space: nowrap;
  letter-spacing: 0.3px;
}
.plabel.sun { color: var(--accent); font-weight: 600; }

#hint {
  position: fixed; bottom: 16px; right: 16px;
  color: var(--muted); font-size: 10.5px; text-align: right;
  pointer-events: none; opacity: 0.7;
}

::-webkit-scrollbar { width: 8px; height: 8px; }
::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.14); border-radius: 4px; }
::-webkit-scrollbar-track { background: transparent; }

@media (max-width: 720px) {
  #controls { display: none; }
  #topbar { max-width: calc(100vw - 28px); }
  #detail { width: calc(100vw - 28px); }
}

toolUseResult.content:
:root {
  --bg: #05060a;
  --panel: rgba(16, 19, 28, 0.86);
  --panel-solid: #11141d;
  --border: rgba(120, 140, 180, 0.18);
  --text: #d6dcec;
  --muted: #8a93a8;
  --accent: #ffd166;
  --pha: #ff6a35;
  --sentry: #ff4dd2;
  --comet: #74f2ff;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  height: 100%;
  overflow: hidden;
  background: var(--bg);
  color: var(--text);
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica,
    Arial, sans-serif;
  font-size: 13px;
  -webkit-font-smoothing: antialiased;
}

#app { position: fixed; inset: 0; }
canvas { display: block; }

/* ---- loading ---- */
#loading {
  position: fixed; inset: 0; z-index: 50;
  display: flex; flex-direction: column; gap: 16px;
  align-items: center; justify-content: center;
  background: var(--bg); color: var(--muted);
}
#loading.hidden { display: none; }
.spinner {
  width: 34px; height: 34px; border-radius: 50%;
  border: 3px solid rgba(255,255,255,0.12);
  border-top-color: var(--accent);
  animation: spin 0.8s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

/* ---- panels ---- */
.panel {
  position: fixed;
  background: var(--panel);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid var(--border);
  border-radius: 12px;
  box-shadow: 0 10px 40px rgba(0,0,0,0.5);
}

/* top bar / title */
#topbar {
  top: 14px; left: 14px;
  padding: 12px 16px;
  max-width: 320px;
}
#topbar h1 {
  margin: 0 0 3px; font-size: 15px; font-weight: 650;
  letter-spacing: 0.2px;
}
#topbar .sub { color: var(--muted); font-size: 11.5px; line-height: 1.45; }
#topbar .counts { margin-top: 8px; display: flex; gap: 12px; flex-wrap: wrap; }
#topbar .counts span { color: var(--muted); }
#topbar .counts b { color: var(--text); font-weight: 600; }

/* ---- controls (left) ---- */
#controls {
  left: 14px; top: 132px;
  width: 290px;
  padding: 14px 16px;
  max-height: calc(100vh - 320px);
  overflow-y: auto;
}
#controls h2 {
  font-size: 11px; text-transform: uppercase; letter-spacing: 0.8px;
  color: var(--muted); margin: 0 0 8px; font-weight: 600;
}
#controls .group { margin-bottom: 16px; }
#controls label { display: block; margin-bottom: 5px; color: var(--muted); font-size: 11.5px; }
#controls input[type="text"],
#controls input[type="date"],
#controls select {
  width: 100%; padding: 7px 9px;
  background: rgba(0,0,0,0.32);
  border: 1px solid var(--border); border-radius: 7px;
  color: var(--text); font-size: 12.5px; font-family: inherit;
}
#controls input[type="range"] { width: 100%; accent-color: var(--accent); }
.row { display: flex; gap: 8px; align-items: center; }
.row > * { flex: 1; }
.chk { display: flex !important; align-items: center; gap: 7px; cursor: pointer; color: var(--text); margin-bottom: 6px; }
.chk input { accent-color: var(--accent); }
.rangeval { color: var(--text); font-variant-numeric: tabular-nums; }
.legend { display: flex; flex-direction: column; gap: 4px; font-size: 11px; }
.legend .dot { display: inline-block; width: 9px; height: 9px; border-radius: 50%; margin-right: 6px; vertical-align: middle; }

button {
  font-family: inherit; cursor: pointer;
  background: rgba(255,255,255,0.06);
  border: 1px solid var(--border); border-radius: 7px;
  color: var(--text); padding: 7px 10px; font-size: 12px;
  transition: background 0.12s, border-color 0.12s;
}
button:hover { background: rgba(255,255,255,0.12); }
button.primary { background: var(--accent); color: #1a1300; border-color: var(--accent); font-weight: 600; }
button.primary:hover { filter: brightness(1.08); }
button.active { background: rgba(255,209,102,0.18); border-color: var(--accent); color: var(--accent); }

/* ---- timebar (bottom) ---- */
#timebar {
  left: 50%; transform: translateX(-50%);
  bottom: 16px;
  padding: 12px 18px;
  width: min(720px, calc(100vw - 28px));
  display: flex; flex-direction: column; gap: 10px;
}
#timebar .line1 { display: flex; align-items: center; gap: 14px; }
#timebar .date { font-size: 16px; font-weight: 600; font-variant-numeric: tabular-nums; min-width: 150px; }
#timebar .rate { color: var(--muted); font-size: 11.5px; }
#timebar .spacer { flex: 1; }
#timebar .btns { display: flex; gap: 6px; }
#playbtn { width: 40px; font-size: 14px; }
#timebar input[type="range"] { width: 100%; accent-color: var(--accent); }
#timebar .scrubwrap { display: flex; align-items: center; gap: 10px; }
#timebar .scrubwrap span { color: var(--muted); font-size: 10.5px; white-space: nowrap; }
.ratebtns { display: flex; gap: 4px; }
.ratebtns button { padding: 4px 8px; font-size: 11px; }

/* ---- detail panel (right) ---- */
#detail {
  right: 14px; top: 14px;
  width: 320px;
  max-height: calc(100vh - 28px);
  display: none;
  flex-direction: column;
}
#detail.open { display: flex; }
#detail .head {
  padding: 14px 16px 10px; border-bottom: 1px solid var(--border);
  display: flex; justify-content: space-between; align-items: flex-start; gap: 8px;
}
#detail .head h2 { margin: 0; font-size: 15px; font-weight: 650; line-height: 1.25; }
#detail .head .desig { color: var(--muted); font-size: 11.5px; margin-top: 2px; }
#detail .close { background: none; border: none; font-size: 18px; color: var(--muted); padding: 0 4px; }
#detail .body { padding: 12px 16px; overflow-y: auto; }
#detail .tags { display: flex; gap: 6px; flex-wrap: wrap; margin-bottom: 12px; }
.tag { font-size: 10.5px; padding: 3px 8px; border-radius: 20px; font-weight: 600; letter-spacing: 0.3px; }
.tag.pha { background: rgba(255,106,53,0.18); color: var(--pha); border: 1px solid rgba(255,106,53,0.4); }
.tag.sentry { background: rgba(255,77,210,0.16); color: var(--sentry); border: 1px solid rgba(255,77,210,0.4); }
.tag.comet { background: rgba(116,242,255,0.14); color: var(--comet); border: 1px solid rgba(116,242,255,0.4); }
.tag.class { background: rgba(120,140,180,0.16); color: #aab6cc; border: 1px solid var(--border); }
.kv { display: grid; grid-template-columns: 1fr auto; gap: 4px 10px; margin-bottom: 14px; }
.kv .k { color: var(--muted); }
.kv .v { text-align: right; font-variant-numeric: tabular-nums; }
#detail h3 { font-size: 11px; text-transform: uppercase; letter-spacing: 0.6px; color: var(--muted); margin: 14px 0 8px; }
.risk { background: rgba(255,77,210,0.08); border: 1px solid rgba(255,77,210,0.25); border-radius: 8px; padding: 10px 12px; margin-bottom: 12px; }
.ca-list { display: flex; flex-direction: column; gap: 6px; max-height: 220px; overflow-y: auto; }
.ca-item { display: grid; grid-template-columns: 1fr auto; gap: 2px 8px; font-size: 11.5px; padding: 7px 9px; background: rgba(0,0,0,0.25); border-radius: 6px; border-left: 2px solid var(--border); }
.ca-item.soon { border-left-color: var(--pha); }
.ca-item .cd { font-weight: 600; }
.ca-item .dist { text-align: right; font-variant-numeric: tabular-nums; }
.ca-item .meta { color: var(--muted); font-size: 10.5px; grid-column: 1 / -1; }
#detail .actions { display: flex; gap: 6px; margin-top: 10px; }
#detail .actions button { flex: 1; }

/* ---- search results dropdown ---- */
#results {
  position: absolute; z-index: 30;
  background: var(--panel-solid);
  border: 1px solid var(--border); border-radius: 8px;
  max-height: 260px; overflow-y: auto;
  width: 258px; margin-top: 2px;
  display: none;
  box-shadow: 0 10px 30px rgba(0,0,0,0.6);
}
#results.open { display: block; }
.result {
  padding: 8px 11px; cursor: pointer; border-bottom: 1px solid rgba(255,255,255,0.04);
  display: flex; justify-content: space-between; gap: 8px;
}
.result:hover { background: rgba(255,255,255,0.07); }
.result .nm { color: var(--text); }
.result .cls { color: var(--muted); font-size: 10.5px; }

/* planet labels */
.plabel {
  position: absolute; transform: translate(-50%, -140%);
  color: #c8d2e6; font-size: 11px; pointer-events: none;
  text-shadow: 0 1px 4px #000; white-space: nowrap;
  letter-spacing: 0.3px;
}
.plabel.sun { color: var(--accent); font-weight: 600; }

#hint {
  position: fixed; bottom: 16px; right: 16px;
  color: var(--muted); font-size: 10.5px; text-align: right;
  pointer-events: none; opacity: 0.7;
}

::-webkit-scrollbar { width: 8px; height: 8px; }
::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.14); border-radius: 4px; }
::-webkit-scrollbar-track { background: transparent; }

@media (max-width: 720px) {
  #controls { display: none; }
  #topbar { max-width: calc(100vw - 28px); }
  #detail { width: calc(100vw - 28px); }
}

input.content:
// DOM construction for the control panels. Pure markup + element lookups;
// behaviour is wired up in main.ts.

export interface UIRefs {
  // topbar
  countAst: HTMLElement;
  countComet: HTMLElement;
  countPha: HTMLElement;
  countShown: HTMLElement;
  // search
  search: HTMLInputElement;
  results: HTMLElement;
  // filters
  fPha: HTMLInputElement;
  fSentry: HTMLInputElement;
  fComets: HTMLInputElement;
  fAsteroids: HTMLInputElement;
  fClass: HTMLSelectElement;
  fDia: HTMLInputElement;
  fDiaVal: HTMLElement;
  fMoid: HTMLInputElement;
  fMoidVal: HTMLElement;
  fReset: HTMLButtonElement;
  color: HTMLSelectElement;
  sizeBoost: HTMLInputElement;
  legend: HTMLElement;
  // time
  date: HTMLElement;
  rateLabel: HTMLElement;
  play: HTMLButtonElement;
  scrub: HTMLInputElement;
  dateInput: HTMLInputElement;
  nowBtn: HTMLButtonElement;
  rateBtns: HTMLElement;
  share: HTMLButtonElement;
  // detail
  detail: HTMLElement;
  // labels
  labels: HTMLElement;
}

export function buildUI(app: HTMLElement, classes: string[]): UIRefs {
  const classOptions = classes
    .map((c) => `<option value="${c}">${c}</option>`)
    .join("");

  app.insertAdjacentHTML(
    "beforeend",
    /* html */ `
    <div id="labels"></div>

    <div id="topbar" class="panel">
      <h1>Near-Earth Orbits</h1>
      <div class="sub">The inner solar system &amp; its near-Earth objects, propagated from orbital elements. Click any body to inspect it.</div>
      <div class="counts">
        <span><b id="c-ast">0</b> asteroids</span>
        <span><b id="c-comet">0</b> comets</span>
        <span><b id="c-pha">0</b> PHAs</span>
        <span><b id="c-shown">0</b> shown</span>
      </div>
    </div>

    <div id="controls" class="panel">
      <div class="group">
        <h2>Search</h2>
        <input id="search" type="text" placeholder="Name or designation…" autocomplete="off" />
        <div id="results"></div>
      </div>

      <div class="group">
        <h2>Filter</h2>
        <label class="chk"><input type="checkbox" id="f-ast" checked /> Show asteroids</label>
        <label class="chk"><input type="checkbox" id="f-comets" checked /> Show comets</label>
        <label class="chk"><input type="checkbox" id="f-pha" /> Potentially hazardous only</label>
        <label class="chk"><input type="checkbox" id="f-sentry" /> Sentry impact-risk only</label>

        <label style="margin-top:8px">Orbit class</label>
        <select id="f-class">
          <option value="">All classes</option>
          ${classOptions}
        </select>

        <label style="margin-top:10px">Min diameter: <span class="rangeval" id="f-dia-val">any</span></label>
        <input type="range" id="f-dia" min="0" max="10" step="0.1" value="0" />

        <label style="margin-top:8px">Max Earth MOID: <span class="rangeval" id="f-moid-val">any</span></label>
        <input type="range" id="f-moid" min="0.005" max="0.5" step="0.005" value="0.5" />

        <button id="f-reset" style="margin-top:10px; width:100%">Reset filters</button>
      </div>

      <div class="group">
        <h2>Display</h2>
        <label>Colour by</label>
        <select id="color">
          <option value="0">Hazard status</option>
          <option value="1">Inclination</option>
          <option value="2">Eccentricity</option>
        </select>
        <label style="margin-top:8px">Point size</label>
        <input type="range" id="sizeboost" min="0.4" max="3" step="0.1" value="1" />
        <div id="legend" class="legend" style="margin-top:10px"></div>
      </div>
    </div>

    <div id="timebar" class="panel">
      <div class="line1">
        <button id="play" title="Play / Pause">⏸</button>
        <div>
          <div class="date" id="date">—</div>
          <div class="rate" id="ratelabel"></div>
        </div>
        <div class="spacer"></div>
        <div class="ratebtns" id="ratebtns">
          <button data-rate="-365">⏪</button>
          <button data-rate="-30">◀</button>
          <button data-rate="1">▶</button>
          <button data-rate="30">▶▶</button>
          <button data-rate="365">⏩</button>
        </div>
      </div>
      <div class="scrubwrap">
        <span id="scrub-min"></span>
        <input type="range" id="scrub" min="0" max="1000" step="1" value="0" />
        <span id="scrub-max"></span>
      </div>
      <div class="line1">
        <input type="date" id="dateinput" />
        <button id="now">Today</button>
        <div class="spacer"></div>
        <button id="share" class="primary">Copy share link</button>
      </div>
    </div>

    <div id="detail" class="panel"></div>
    <div id="hint">Drag to orbit · scroll to zoom · click a body to inspect</div>
  `
  );

  const $ = <T extends HTMLElement>(id: string) =>
    document.getElementById(id) as T;

  return {
    countAst: $("c-ast"),
    countComet: $("c-comet"),
    countPha: $("c-pha"),
    countShown: $("c-shown"),
    search: $("search"),
    results: $("results"),
    fPha: $("f-pha"),
    fSentry: $("f-sentry"),
    fComets: $("f-comets"),
    fAsteroids: $("f-ast"),
    fClass: $("f-class"),
    fDia: $("f-dia"),
    fDiaVal: $("f-dia-val"),
    fMoid: $("f-moid"),
    fMoidVal: $("f-moid-val"),
    fReset: $("f-reset"),
    color: $("color"),
    sizeBoost: $("sizeboost"),
    legend: $("legend"),
    date: $("date"),
    rateLabel: $("ratelabel"),
    play: $("play"),
    scrub: $("scrub"),
    dateInput: $("dateinput"),
    nowBtn: $("now"),
    rateBtns: $("ratebtns"),
    share: $("share"),
    detail: $("detail"),
    labels: $("labels"),
  };
}

const LEGEND_HAZARD = [
  ["#94a2bd", "Near-Earth asteroid"],
  ["#ff6a35", "Potentially hazardous"],
  ["#ff4dd2", "Sentry impact risk"],
  ["#74f2ff", "Comet"],
];

export function legendHTML(colorMode: number): string {
  if (colorMode === 1)
    return gradientLegend("Inclination", "0°", "≥50°");
  if (colorMode === 2) return gradientLegend("Eccentricity", "0", "1");
  return LEGEND_HAZARD.map(
    ([c, t]) => `<div><span class="dot" style="background:${c}"></span>${t}</div>`
  ).join("");
}

function gradientLegend(label: string, lo: string, hi: string): string {
  return `<div style="color:var(--muted);margin-bottom:2px">${label}</div>
    <div style="height:10px;border-radius:5px;background:linear-gradient(90deg,#3b6bd6,#37e0d6,#ffe14d,#ff4030)"></div>
    <div style="display:flex;justify-content:space-between;color:var(--muted);font-size:10px;margin-top:2px"><span>${lo}</span><span>${hi}</span></div>
    <div style="margin-top:6px"><span class="dot" style="background:#74f2ff"></span>Comet</div>`;
}

