18	    .map(([k, v]) => `<div class="k">${k}</div><div class="v">${v}</div>`)
19	    .join("")}</div>`;
20	}
21	
22	function header(title: string, desig: string): string {
23	  return `
24	    <div class="head">
25	      <div>
26	        <h2>${title}</h2>
27	        <div class="desig">${desig}</div>
28	      </div>
29	      <button class="close" id="d-close" title="Close">×</button>
30	    </div>`;
31	}
32	
33	function actions(followable: boolean, following: boolean): string {
34	  return `<div class="actions">
35	    ${
36	      followable
37	        ? `<button id="d-follow" class="${following ? "active" : ""}">${
38	            following ? "Following ✓" : "Follow"
39	          }</button>`
40	        : ""
41	    }
42	    <button id="d-frame">Focus</button>
43	  </div>`;
44	}
45	
46	function sentryBox(s: SentryRow): string {
47	  const ipPct = (s.ip * 100).toExponential(2);
48	  return `<div class="risk">
49	    <div style="color:var(--sentry);font-weight:600;margin-bottom:6px">⚠ CNEOS Sentry impact risk</div>
50	    ${kv([
51	      ["Impact probability", `${ipPct}%`],
52	      ["Potential impacts", String(s.n_imp)],
53	      ["Window", s.range],
54	      ["Palermo scale (cum)", fmt(s.ps_cum, "", 2)],
55	      ["Palermo scale (max)", fmt(s.ps_max, "", 2)],
56	      ["Torino scale", String(s.ts_max)],
57	      ["Encounter velocity", fmt(s.v_inf, " km/s", 1)],
58	    ])}
59	  </div>`;
60	}
61	
62	function caList(approaches: CloseApproach[], nowJd: number): string {
63	  if (!approaches.length)
64	    return `<div style="color:var(--muted);font-size:11.5px">No recorded close approaches.</div>`;
65	  // show a window around "now": up to 5 past + next 12 upcoming
66	  const idx = approaches.findIndex((a) => a.jd >= nowJd);
67	  const start = idx < 0 ? Math.max(0, approaches.length - 8) : Math.max(0, idx - 4);
68	  const slice = approaches.slice(start, start + 16);
69	  const items = slice
70	    .map((a) => {
71	      const soon = a.jd >= nowJd;
72	      const ld = a.dist * 389.2; // au -> lunar distances
73	      return `<div class="ca-item ${soon ? "soon" : ""}">
74	        <div class="cd">${a.cd}</div>
75	        <div class="dist">${a.dist.toFixed(5)} au</div>
76	        <div class="meta">${ld.toFixed(1)} LD · ${a.v.toFixed(1)} km/s${
77	        a.dmin ? ` · 3σ min ${a.dmin.toFixed(5)} au` : ""
78	      }</div>
79	      </div>`;
80	    })
81	    .join("");
82	  return `<div class="ca-list">${items}</div>
83	    <div style="color:var(--muted);font-size:10px;margin-top:6px">${approaches.length} total events · LD = lunar distance</div>`;
84	}
85	
86	export function renderAsteroid(
87	  a: AsteroidMeta,
88	  sentry: SentryRow | undefined,
89	  approaches: CloseApproach[],
90	  nowJd: number,
91	  following: boolean
92	): string {
93	  const tags = [
94	    `<span class="tag class">${a.c}</span>`,
95	    a.pha ? `<span class="tag pha">PHA</span>` : "",
96	    sentry ? `<span class="tag sentry">SENTRY</span>` : "",
97	  ].join("");
98	
99	  return (
100	    header(a.nm || a.n, a.n) +
101	    `<div class="body">
102	      <div class="tags">${tags}</div>
103	      ${sentry ? sentryBox(sentry) : ""}
104	      <h3>Physical</h3>
105	      ${kv([
106	        ["Diameter", fmt(a.dia, " km")],
107	        ["Absolute mag (H)", fmt(a.H, "", 2)],
108	        ["Albedo", fmt(a.alb, "", 3)],
109	        ["Rotation period", fmt(a.rot, " h", 2)],
110	        ["Spectral type", a.spec || "—"],
111	        ["First observed", a.obs || "—"],
112	      ])}
113	      <h3>Orbit</h3>
114	      ${kv([
115	        ["Semi-major axis", fmt(a.a, " au")],
116	        ["Eccentricity", fmt(a.e, "", 4)],
117	        ["Inclination", fmt(a.inc, "°", 2)],
118	        ["Perihelion (q)", fmt(a.q, " au")],
119	        ["Aphelion (Q)", fmt(a.ad, " au")],
120	        ["Period", a.per ? `${(a.per / 365.25).toFixed(2)} yr` : "—"],
121	        ["Earth MOID", fmt(a.moid, " au", 4)],
122	      ])}
123	      <h3>Close approaches to Earth</h3>
124	      ${caList(approaches, nowJd)}
125	      ${actions(true, following)}
126	    </div>`
127	  );
128	}
129	
130	export function renderComet(
131	  c: CometMeta,
132	  approaches: CloseApproach[],
133	  nowJd: number,
134	  following: boolean
135	): string {
136	  const orbitKind =
137	    c.e < 1 ? "Elliptical" : c.e > 1 ? "Hyperbolic" : "Parabolic";
138	  return (
139	    header(c.n, c.d) +
140	    `<div class="body">
141	      <div class="tags">
142	        <span class="tag comet">COMET</span>
143	        <span class="tag class">${c.c}</span>
144	        <span class="tag class">${orbitKind}</span>
145	      </div>
146	      <h3>Orbit</h3>
147	      ${kv([
148	        ["Semi-major axis", c.a != null ? fmt(c.a, " au") : "∞"],
149	        ["Eccentricity", fmt(c.e, "", 4)],
150	        ["Inclination", fmt(c.inc, "°", 2)],
151	        ["Perihelion (q)", fmt(c.q, " au")],
152	        ["Period", c.per ? `${(c.per / 365.25).toFixed(1)} yr` : "—"],
153	        ["Perihelion passage", formatDate(jdToDate(c.tp))],
154	      ])}
155	      <h3>Physical</h3>
156	      ${kv([
157	        ["Total magnitude (M1)", fmt(c.M1, "", 2)],
158	        ["Diameter", fmt(c.dia, " km")],
159	      ])}
160	      ${
161	        approaches.length
162	          ? `<h3>Close approaches to Earth</h3>${caList(approaches, nowJd)}`
163	          : ""
164	      }
165	      ${actions(true, following)}
166	    </div>`
167	  );
168	}
169	
170	export function renderPlanet(p: PlanetRow): string {
171	  return (
172	    header(p.name, "Planet") +
173	    `<div class="body">
174	      <div class="tags"><span class="tag class">PLANET</span></div>
175	      <h3>Orbit</h3>
176	      ${kv([
177	        ["Semi-major axis", fmt(p.a, " au")],
178	        ["Eccentricity", fmt(p.e, "", 4)],
179	        ["Inclination", fmt(p.i, "°", 2)],
180	        ["Period", `${(p.per / 365.25).toFixed(2)} yr`],
181	        ["Mean radius", `${p.radius_km.toLocaleString()} km`],
182	      ])}
183	      ${actions(true, false)}
184	    </div>`
185	  );
186	}

