// Headless-Chrome smoke test via CDP. Captures console + exceptions, screenshot.
import { spawn } from "node:child_process";
import { writeFileSync } from "node:fs";

const URL = process.argv[2] || "http://localhost:8123/";
const OUT = process.argv[3] || "shot.png";
const CHROME =
  "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome";

const chrome = spawn(CHROME, [
  "--headless=new",
  "--remote-debugging-port=9222",
  "--disable-gpu=false",
  "--enable-unsafe-swiftshader",
  "--use-gl=angle",
  "--use-angle=swiftshader",
  "--window-size=1400,900",
  "--no-first-run",
  "--no-sandbox",
  "--user-data-dir=/tmp/chrome-smoke-prof",
  "about:blank",
]);
chrome.stderr.on("data", () => {});

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

async function getWsUrl() {
  for (let i = 0; i < 40; i++) {
    try {
      const r = await fetch("http://localhost:9222/json/version");
      const j = await r.json();
      if (j.webSocketDebuggerUrl) return j.webSocketDebuggerUrl;
    } catch {}
    await sleep(250);
  }
  throw new Error("chrome devtools not reachable");
}

let msgId = 0;
function send(ws, method, params = {}, sessionId) {
  const id = ++msgId;
  ws.send(JSON.stringify({ id, method, params, sessionId }));
  return id;
}

const logs = [];
const errors = [];

async function run() {
  const wsUrl = await getWsUrl();
  const ws = new WebSocket(wsUrl);
  await new Promise((res) => (ws.onopen = res));

  let sessionId;
  const waiters = new Map();

  ws.onmessage = (ev) => {
    const m = JSON.parse(ev.data);
    if (m.method === "Target.attachedToTarget") {
      sessionId = m.params.sessionId;
    }
    if (m.method === "Runtime.consoleAPICalled") {
      const a = (m.params.args || [])
        .map((x) => x.value ?? x.description ?? x.type)
        .join(" ");
      logs.push(`[${m.params.type}] ${a}`);
    }
    if (m.method === "Runtime.exceptionThrown") {
      const d = m.params.exceptionDetails;
      errors.push(d.exception?.description || d.text);
    }
    if (m.method === "Log.entryAdded") {
      const e = m.params.entry;
      if (e.level === "error") errors.push(`[log] ${e.text}`);
    }
    if (m.id && waiters.has(m.id)) {
      waiters.get(m.id)(m.result);
      waiters.delete(m.id);
    }
  };
  const call = (method, params, sid) =>
    new Promise((res) => {
      const id = send(ws, method, params, sid);
      waiters.set(id, res);
    });

  // attach to the page target
  const { targetInfos } = await call("Target.getTargets");
  const page = targetInfos.find((t) => t.type === "page");
  const att = await call("Target.attachToTarget", {
    targetId: page.targetId,
    flatten: true,
  });
  const sid = att.sessionId;

  await call("Runtime.enable", {}, sid);
  await call("Log.enable", {}, sid);
  await call("Page.enable", {}, sid);
  await call("Network.enable", {}, sid);
  await call("Page.navigate", { url: URL }, sid);

  await sleep(8000); // let data load + render

  const shot = await call(
    "Page.captureScreenshot",
    { format: "png" },
    sid
  );
  if (shot?.data) writeFileSync(OUT, Buffer.from(shot.data, "base64"));

  // probe page state
  const probe = await call(
    "Runtime.evaluate",
    {
      expression: `JSON.stringify({
        loadingHidden: document.getElementById('loading')?.classList.contains('hidden'),
        canvas: !!document.querySelector('canvas'),
        astCount: document.getElementById('c-ast')?.textContent,
        shown: document.getElementById('c-shown')?.textContent,
        date: document.getElementById('date')?.textContent,
      })`,
      returnByValue: true,
    },
    sid
  );

  console.log("PROBE:", probe?.result?.value);
  console.log("CONSOLE LOGS:");
  for (const l of logs) console.log("  ", l);
  console.log("ERRORS:");
  for (const e of errors) console.log("  ", e);

  ws.close();
  chrome.kill();
  process.exit(0);
}

run().catch((e) => {
  console.error("smoke failed:", e);
  chrome.kill();
  process.exit(1);
});

