  ws=new WebSocket(await wsUrl());await new Promise(r=>ws.onopen=r);
  ws.onmessage=(ev)=>{const m=JSON.parse(ev.data);if(m.method==="Runtime.exceptionThrown")errors.push(m.params.exceptionDetails.exception?.description||m.params.exceptionDetails.text);if(m.id&&waiters.has(m.id)){waiters.get(m.id)(m.result);waiters.delete(m.id);}};
  const {targetInfos}=await call("Target.getTargets");
  const page=targetInfos.find(t=>t.type==="page");
