  await call("Runtime.enable",{},sid);await call("Page.enable",{},sid);
  await call("Page.navigate",{url:URL},sid);await sleep(7000);
  const evalx=(expr)=>call("Runtime.evaluate",{expression:expr,returnByValue:true,awaitPromise:true},sid);
  // type "Eros" in search and click first result
  await evalx(`(()=>{const s=document.getElementById('search');s.value='Eros';s.dispatchEvent(new Event('input',{bubbles:true}));})()`);
  await sleep(400);
  const res1=await evalx(`(()=>{const r=document.querySelector('#results .result[data-i]');if(!r)return 'NO RESULT';r.dispatchEvent(new MouseEvent('click',{bubbles:true}));return 'clicked '+r.textContent;})()`);
  console.log("search:",res1?.result?.value);
  await sleep(1500); // close approaches lazy load
  const det=await evalx(`(()=>{const d=document.getElementById('detail');return JSON.stringify({open:d.classList.contains('open'),title:d.querySelector('h2')?.textContent,nCA:d.querySelectorAll('.ca-item').length,hasOrbit:!!d.querySelector('.kv')});})()`);
