  await sleep(600);
  shot=await call("Page.captureScreenshot",{format:"png"},sid);
  if(shot?.data)writeFileSync(SP+"/incl.png",Buffer.from(shot.data,"base64"));
  console.log("ERRORS:",errors);
  ws.close();chrome.kill();process.exit(0);
}
